#include <bits/stdc++.h>
using namespace std;
const int maxn = 200010;
int n, q, cnt;
int head[maxn], dep[maxn], f[maxn][23], lg[maxn];
struct Edge {
    int v, nxt;
} e[maxn << 2];
inline int read() {
    int x = 0, f = 1;
    char ch = getchar();
    while (ch < '0' || ch > '9') {
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while (ch >= '0' && ch <= '9') {
        x = x * 10 + ch - '0';
        ch = getchar();
    }
    return x * f;
}
inline void add(int u, int v) {
    e[++cnt].v = v;
    e[cnt].nxt = head[u];
    head[u] = cnt;
}

void dfs(int now, int fa) {
    dep[now] = dep[fa] + 1;
    f[now][0] = fa;
    for (int i = 1; (1 << i) <= dep[now]; ++i) {
        f[now][i] = f[f[now][i - 1]][i - 1];
    }
    for (int i = head[now]; i; i = e[i].nxt) {
        int ev = e[i].v;
        if (ev == fa) continue;
        dfs(ev, now);
    }
}
int lca(int x, int y) {
    if (dep[y] > dep[x]) swap(x, y);
    for (int i = lg[dep[x] - dep[y]]; i >= 0; --i) {
        if (dep[f[x][i]] < dep[y]) continue;
        x = f[x][i];
    }
    if (x == y) return x;
    for (int i = lg[dep[x] - 1]; i >= 0; --i) {
        if (f[x][i] == f[y][i]) continue;
        x = f[x][i];
        y = f[y][i];
    }
    return f[x][0];
}
void pre() {
    int tmp1 = 1, tmp2 = 0;
    while (tmp1 <= n) {
        lg[tmp1] = tmp2;
        tmp2++;
        tmp1 *= 2;
    }
    for (int i = 1; i <= n; ++i) {
        if (lg[i]) continue;
        lg[i] = lg[i - 1];
    }
}
int dis(int a, int b) {
    int c = lca(a, b);
    return abs(dep[a] - dep[c]) + abs(dep[b] - dep[c]);
}
int main() {
    n = read(), q = read();
    pre();
    for (int i = 1; i < n; ++i) {
        int x = read(), y = read();
        add(x, y);
        add(y, x);
    }
    dfs(1, 0);
    for (int i = 1; i <= q; ++i) {
        int a = read(), b = read(), c = read(), d = read();
        int tmp1 = lca(a, b);
        int tmp2 = lca(c, d);
        if (dis(a, tmp2) + dis(b, tmp2) == dis(a, b) || dis(c, tmp1) + dis(d, tmp1) == dis(c, d)) {
            printf("Y\n");
        } else {
            printf("N\n");
        }
    }
    return 0;
}
